t.created_at >= #{cutoffAt}

    AND t.scope = #{scope}


    AND t.status = #{status}


    AND t.provider_source = #{providerSource}


    AND t.model_name LIKE CONCAT('%', #{modelName}, '%')


    AND t.error_code = #{errorCode}

mapper.select:
SELECT

FROM app_voice_stat_event t
WHERE t.created_at >= #{cutoffAt}
